class Solution {
    public int maxValue(int n, int index, int maxSum) {
        int left = 1, right = maxSum;
        while (left < right) {
            int mid = left + (right - left) / 2;
            long sum = (long)mid * (mid + 1) / 2;
            if (index < mid) sum += (long)(mid - index);
            if (n - index - 1 < mid) sum += (long)(mid - (n - index - 1));
            if (sum > maxSum) right = mid;
            else left = mid + 1;
        }
        return left - 1;
    }
}
